#include <stdio.h>

int isPerfectNumber(int num) {
    int sum = 0;

    for (int i = 1; i < num; i++) {
        if (num % i == 0) {
            sum += i;
        }
    }

    if (sum == num) {
        return 1;
    } else {
        return 0;
    }
}

int main() {
    int m, n;

    scanf("%d %d", &m, &n);

    int found = 0;

    for (int num = m; num <= n; num++) {
        if (isPerfectNumber(num)) {
            printf("%4d =", num);

            for (int i = 1; i < num; i++) {
                if (num % i == 0) {
                    printf(" %d", i);
                    if (i != num / i) {
                        printf("+");
                    }
                }
            }

            printf("\n");

            found = 1;
        }
    }

    if (!found) {
        printf("Not Found");
    }

    return 0;
}

