#include <stdbool.h>

bool isPrime(int num) {
    if (num <= 1) {
        return false;
    }

    for (int i = 2; i * i <= num; i++) {
        if (num % i == 0) {
            return false;
        }
    }

    return true;
}

int main() {
    int n;

    scanf("%d", &n);

    int num = n + 1;

    while (!isPrime(num)) {
        num++;
    }

    printf("%d", num);

    return 0;
}

#include <stdio.h>

int isomorphismNumber(int num) {
    int square = num * num;

    while (num > 0) {
        if (num % 10 != square % 10) {
            return 0;
        }

        num /= 10;
        square /= 10;
    }

    return 1;
}

int main() {
    int n;

    scanf("%d", &n);

    int found = 0;

    for (int num = 1; num <= n; num++) {
        if (isomorphismNumber(num)) {
            if (found) {
                printf(" ");
            }

            printf("%d", num);
            found = 1;
        }
    }

    return 0;
}

#include <stdio.h>

// 求最大公约数（辗转相除法）
int gcd(int a, int b) {
    int temp;

    while (b > 0) {
        temp = a % b;
        a = b;
        b = temp;
    }

    return a;
}

// 约分为最简分数
void simplifyFraction(int *numerator, int *denominator) {
    int commonFactor = gcd(*numerator, *denominator);

    *numerator /= commonFactor;
    *denominator /= commonFactor;
}

int main() {
    int numerator, denominator;

    scanf("%d/%d", &numerator, &denominator);

    simplifyFraction(&numerator, &denominator);

    printf("%d/%d", numerator, denominator);

    return 0;
}

#include <stdio.h>

void primeFactorization(int n) {
    int factor = 2;

    while (n > 1) {
        if (n % factor == 0) {
            printf("%d", factor);
            n /= factor;

            if (n > 1) {
                printf("*");
            }
        } else {
            factor++;
        }
    }
}

int main() {
    int n;

    scanf("%d", &n);

    primeFactorization(n);

    return 0;
}

#include <stdio.h>

int main() {
    int L, H, S;

    scanf("%d %d %d", &L, &H, &S);

    if (L > H) {
        int temp = L;
        L = H;
        H = temp;
    }

    printf(" Comparison Table\n");

    for (int fahrenheit = L; fahrenheit <= H; fahrenheit += S) {
        double celsius = 5.0 / 9.0 * (fahrenheit - 32);

        printf("%4d ...... %.2lf\n", fahrenheit, celsius);
    }

    return 0;
}

#include <stdio.h>

int main() {
    int n;

    scanf("%d", &n);

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < i; j++) {
            printf(" ");
        }

        for (int k = 0; k < 2 * (n - i) - 1; k++) {
            printf("*");
        }

        printf("\n");
    }

    return 0;
}

#include <stdio.h>

int main() {
    int n = 4;

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n - i; j++) {
            printf(" ");
        }

        for (int k = 1; k <= i; k++) {
            printf("%d", k);
        }

        for (int l = i - 1; l >= 1; l--) {
            printf("%d", l);
        }

        printf("\n");
    }

    return 0;
}

#include <stdio.h>

int main() {
    int days, weekday;

    scanf("%d %d", &days, &weekday);

    printf(" Sun Mon Tue Wed Thu Fri Sat\n");

    for (int i = 0; i < weekday; i++) {
        printf("    ");
    }

    for (int day = 1; day <= days; day++) {
        printf("%4d", day);

        weekday++;

        if (weekday == 7) {
            weekday = 0;
            printf("\n");
        }
    }

    return 0;
}

